{"method_body":"{
  repeated_str := "";
  var k := 0;
  while k < n
    invariant 0 <= k <= n
    invariant |repeated_str| == k * |str|
    invariant forall i :: 0 <= i < k ==> repeated_str[i * |str| .. (i + 1) * |str|] == str
  {
    var prev := repeated_str;
    var kk := k;

    assert |prev| == kk * |str|;
    forall i | 0 <= i < kk
      ensures prev[i * |str| .. (i + 1) * |str|] == str
    {
      assert 0 <= i < k;
      assert prev == repeated_str;
      assert repeated_str[i * |str| .. (i + 1) * |str|] == str;
    }

    repeated_str := prev + str;

    assert repeated_str == prev + str;
    assert |repeated_str| == |prev| + |str|;
    assert (kk + 1) * |str| == kk * |str| + |str|;
    assert |repeated_str| == (kk + 1) * |str|;
    assert |prev| <= |repeated_str|;
    assert repeated_str[..|prev|] == prev;
    assert repeated_str[|prev|..|repeated_str|] == str;

    forall i | 0 <= i < kk + 1
      ensures repeated_str[i * |str| .. (i + 1) * |str|] == str
    {
      var a := i * |str|;
      var b := (i + 1) * |str|;
      assert 0 <= |str|;
      assert 0 <= a <= b;
      if i < kk {
        assert i + 1 <= kk;
        assert b <= kk * |str|;
        assert b <= |prev|;
        assert repeated_str[a..b] == repeated_str[..|prev|][a..b];
        assert repeated_str[..|prev|][a..b] == prev[a..b];
        assert prev[a..b] == str;
      } else {
        assert i == kk;
        assert a == |prev|;
        assert b == |repeated_str|;
        assert repeated_str[a..b] == str;
      }
    }

    k := k + 1;
    assert k == kk + 1;
  }
  assert k == n;
}"}

